import requests
from requests.auth import HTTPBasicAuth

# Configuration
rabbitmq_host = 'http://localhost:15672'
username = 'admin'
password = 'admin_password'

# Define vhosts and users
vhosts = ['app1_vhost', 'app2_vhost']
users = [
    {'name': 'app1_user', 'password': 'app1_password', 'vhost': 'app1_vhost'},
    {'name': 'app2_user', 'password': 'app2_password', 'vhost': 'app2_vhost'}
]

# Create vhosts
for vhost in vhosts:
    response = requests.put(f'{rabbitmq_host}/api/vhosts/{vhost}', auth=HTTPBasicAuth(username, password))
    if response.status_code == 204:
        print(f'Vhost {vhost} created successfully.')
    else:
        print(f'Failed to create vhost {vhost}: {response.text}')

# Create users and set permissions
for user in users:
    # Create user
    user_data = {
        'password': user['password'],
        'tags': 'management'
    }
    response = requests.put(f'{rabbitmq_host}/api/users/{user["name"]}', json=user_data, auth=HTTPBasicAuth(username, password))
    if response.status_code == 204:
        print(f'User {user["name"]} created successfully.')
    else:
        print(f'Failed to create user {user["name"]}: {response.text}')

    # Set permissions
    permissions_data = {
        'configure': '.*',
        'write': '.*',
        'read': '.*'
    }
    response = requests.put(f'{rabbitmq_host}/api/permissions/{user["vhost"]}/{user["name"]}', json=permissions_data, auth=HTTPBasicAuth(username, password))
    if response.status_code == 204:
        print(f'Permissions set for user {user["name"]} on vhost {user["vhost"]}.')
    else:
        print(f'Failed to set permissions for user {user["name"]} on vhost {user["vhost"]}: {response.text}')